-- ============================================================
-- 데이터베이스 생성 SQL
-- 생성일: 2026-04-05
-- ============================================================

CREATE DATABASE IF NOT EXISTS capstone_db
    CHARACTER SET utf8mb4
    COLLATE utf8mb4_unicode_ci;

USE capstone_db;

-- ============================================================
-- 1. user 테이블
-- ============================================================
CREATE TABLE IF NOT EXISTS user (
    user_id     VARCHAR(20)  NOT NULL COMMENT '사용자 ID',
    password    VARCHAR(64)  NOT NULL COMMENT '비밀번호 (SHA-256 해시)',
    role        ENUM('student', 'admin') NOT NULL DEFAULT 'student' COMMENT '사용자 권한',
    PRIMARY KEY (user_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='사용자 계정';

-- ============================================================
-- 2. student_profile 테이블
-- ============================================================
CREATE TABLE IF NOT EXISTS student_profile (
    user_id          VARCHAR(20)      NOT NULL COMMENT '사용자 ID (FK)',
    student_id       INT              NOT NULL COMMENT '학번',
    name             VARCHAR(50)      NOT NULL COMMENT '이름',
    phone            VARCHAR(20)          NULL COMMENT '전화번호',
    email_add        VARCHAR(100)         NULL COMMENT '이메일',
    major            VARCHAR(50)          NULL COMMENT '전공',
    current_semester TINYINT UNSIGNED NOT NULL DEFAULT 1 COMMENT '현재 학기',
    status           VARCHAR(10)      NOT NULL COMMENT '재학 상태 (재학/휴학)',
    PRIMARY KEY (student_id),
    UNIQUE  KEY uq_sp_user_id (user_id),
    CONSTRAINT fk_sp_user FOREIGN KEY (user_id) REFERENCES user(user_id)
        ON UPDATE CASCADE ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='학생 프로필';

-- ============================================================
-- 3. enrollment 테이블
-- ============================================================
CREATE TABLE IF NOT EXISTS enrollment (
    id               BIGINT UNSIGNED  NOT NULL AUTO_INCREMENT COMMENT 'PK',
    student_id       INT              NOT NULL COMMENT '학번 (FK)',
    current_semester TINYINT UNSIGNED NOT NULL COMMENT '수강 학기',
    course_name      VARCHAR(100)     NOT NULL COMMENT '과목명',
    course_professor VARCHAR(50)          NULL COMMENT '담당 교수',
    course_grade     DECIMAL(3,1)         NULL COMMENT '과목 성적',
    PRIMARY KEY (id),
    CONSTRAINT fk_enr_student FOREIGN KEY (student_id) REFERENCES student_profile(student_id)
        ON UPDATE CASCADE ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='수강 내역';

-- ============================================================
-- 4. registration 테이블  (원본 파일명: registrarion.csv)
-- ============================================================
CREATE TABLE IF NOT EXISTS registration (
    id           BIGINT UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'PK',
    student_id   INT             NOT NULL COMMENT '학번 (FK)',
    reg_status   VARCHAR(20)     NOT NULL COMMENT '등록 처리 상태 (완료/미납/취소대기)',
    status       VARCHAR(10)     NOT NULL COMMENT '재학 상태',
    paid_amount  INT UNSIGNED    NOT NULL DEFAULT 0 COMMENT '납부 금액',
    reg_date     DATE                NULL COMMENT '등록일',
    PRIMARY KEY (id),
    CONSTRAINT fk_reg_student FOREIGN KEY (student_id) REFERENCES student_profile(student_id)
        ON UPDATE CASCADE ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='등록 정보';

-- ============================================================
-- 5. grade 테이블
-- ============================================================
CREATE TABLE IF NOT EXISTS grade (
    id             BIGINT UNSIGNED  NOT NULL AUTO_INCREMENT COMMENT 'PK',
    student_id     INT              NOT NULL COMMENT '학번 (FK)',
    semester       TINYINT UNSIGNED NOT NULL COMMENT '학기',
    course_name    VARCHAR(100)     NOT NULL COMMENT '과목명',
    course_grade   DECIMAL(3,1)         NULL COMMENT '과목 성적',
    semester_grade DECIMAL(4,2)         NULL COMMENT '학기 평균 성적',
    avg_grade      DECIMAL(4,2)         NULL COMMENT '전체 평균 성적',
    PRIMARY KEY (id),
    CONSTRAINT fk_grade_student FOREIGN KEY (student_id) REFERENCES student_profile(student_id)
        ON UPDATE CASCADE ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='성적 정보';

